const { Pool } = require('pg');
const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const questions = [
{s:'np5',t:'Psychiatric Nursing',q:'Mr. Marquez reports losing his job, not being able to sleep, and feeling upset with his wife. Nurse John responds, "You may want to talk about your employment situation in group today." The Nurse is using which therapeutic technique?',c:['Observations','Restating','Exploring','Focusing'],ci:3,r:'The nurse is using focusing by suggesting that the client discuss a specific issue. The nurse did not restate the question, make observation, or ask further question (exploring).'},
{s:'np5',t:'Psychiatric Nursing',q:'Tony refuses his evening dose of Haloperidol (Haldol), then becomes extremely agitated in the dayroom while other clients are watching television. He begins cursing and throwing furniture. Nurse Oliver\'s first action is to:',c:['Check the client\'s medical record for an order for an as-needed I.M. dose of medication for agitation.','Place the client in full leather restraints.','Call the attending physician and report the behavior.','Remove all other clients from the dayroom.'],ci:3,r:'The nurse\'s first priority is to consider the safety of the clients in the therapeutic setting. The other actions are appropriate responses after ensuring the safety of other clients.'},
{s:'np5',t:'Psychiatric Nursing',q:'Tina who is manic, but not yet on medication, comes to the drug treatment center. The nurse would not let this client join the group session because:',c:['The client is disruptive.','The client is harmful to self.','The client is harmful to others.','The client needs to be on medication first.'],ci:0,r:'Group activity provides too much stimulation, which the client will not be able to handle (harmful to self) and as a result will be disruptive to others.'},
{s:'np5',t:'Psychiatric Nursing',q:'Dervid, an adolescent boy was admitted for substance abuse and hallucinations. The client\'s mother asks Nurse Armando to talk with his husband. The most appropriate nursing intervention would be to:',c:['Inform the mother that she and the father can work through this problem themselves.','Refer the mother to the hospital social worker.','Agree to talk with the mother and the father together.','Suggest that the father and son work things out.'],ci:2,r:'By agreeing to talk with both parents, the nurse can provide emotional support and further assess and validate the family\'s needs.'},
{s:'np5',t:'Psychiatric Nursing',q:'What is Nurse John likely to note in a male client being admitted for alcohol withdrawal?',c:['Perceptual disorders.','Impending coma.','Recent alcohol intake.','Depression with mutism.'],ci:0,r:'Frightening visual hallucinations are especially common in clients experiencing alcohol withdrawal.'},
{s:'np5',t:'Psychiatric Nursing',q:'Airah has taken amitriptyline HCL (Elavil) for 3 days but now says it doesn\'t help and refuses to take it. What should the nurse say or do?',c:['Withhold the drug.','Record the client\'s response.','Encourage the client to tell the doctor.','Suggest that it takes a while before seeing the results.'],ci:3,r:'The client needs a specific response; that it takes 2 to 3 weeks (a delayed effect) until the therapeutic blood level is reached.'},
{s:'np5',t:'Psychiatric Nursing',q:'Dervid, an adolescent has a history of truancy and borrowing other people\'s things without permission. This behavior may be largely attributed to a developmental defect related to the:',c:['Id','Ego','Superego','Oedipal complex'],ci:2,r:'This behavior shows a weak sense of moral consciousness. According to Freudian theory, personality disorders stem from a weak superego.'},
{s:'np5',t:'Psychiatric Nursing',q:'In preparing a female client for electroconvulsive therapy (ECT), Nurse Michelle knows that succinylcoline (Anectine) will be administered for which therapeutic effect?',c:['Short-acting anesthesia','Decreased oral and respiratory secretions.','Skeletal muscle paralysis.','Analgesia.'],ci:2,r:'Anectine is a depolarizing muscle relaxant causing paralysis. It is used to reduce the intensity of muscle contractions during the convulsive stage, thereby reducing the risk of bone fractures or dislocation.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Gina is aware that the dietary implications for a client in manic phase of bipolar disorder is:',c:['Serve the client a bowl of soup, buttered French bread, and apple slices.','Increase calories, decrease fat, and decrease protein.','Give the client pieces of cut-up steak, carrots, and an apple.','Increase calories, carbohydrates, and protein.'],ci:3,r:'This client increased protein for tissue building and increased calories to replace what is burned up (usually via carbohydrates).'},
{s:'np5',t:'Psychiatric Nursing',q:'What parental behavior toward a child during an admission procedure should cause Nurse Ron to suspect child abuse?',c:['Flat affect','Expressing guilt','Acting overly solicitous toward the child.','Ignoring the child.'],ci:2,r:'This behavior is an example of reaction formation, a coping mechanism.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Lynnette notices that a female client with OCD washes her hands for long periods each day. How should the nurse respond to this compulsive behavior?',c:['By designating times during which the client can focus on the behavior.','By urging the client to reduce the frequency of the behavior as rapidly as possible.','By calling attention to or attempting to prevent the behavior.','By discouraging the client from verbalizing anxieties.'],ci:0,r:'The nurse should designate times during which the client can focus on the compulsive behavior. The nurse should urge the client to reduce the frequency gradually, not rapidly. Trying to prevent the behavior may cause pain and terror in the client.'},
{s:'np5',t:'Psychiatric Nursing',q:'Ruby who was raped while walking her dog is diagnosed with PTSD. Three months later she returns complaining of fear, loss of control, and helpless feelings. Which nursing intervention is most appropriate?',c:['Recommending a high-protein, low-fat diet.','Giving sleep medication, as prescribed, to restore a normal sleep-wake cycle.','Allowing the client time to heal.','Exploring the meaning of the traumatic event with the client.'],ci:3,r:'The client with PTSD needs encouragement to examine and understand the meaning of the traumatic event and consequent losses. The client must explore the meaning of the event and won\'t heal without this, no matter how much time passes.'},
{s:'np5',t:'Psychiatric Nursing',q:'Meryl, age 19, is diagnosed with conversion disorder. She asks the nurse, "Why has this happened to me?" What is the nurse\'s best response?',c:['"You\'ve developed this paralysis so you can stay with your parents."','"It must be awful not to be able to move your legs."','"Your problem is real but there is no physical basis for it. We\'ll work on what is going on in your life to find out why it\'s happened."','"It isn\'t uncommon for someone with your personality to develop a conversion disorder."'],ci:2,r:'The nurse must be honest with the client by telling her that the paralysis has no physiologic cause while also conveying empathy and acknowledging that her symptoms are real.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Krina knows that the following drugs have been known to be effective in treating obsessive-compulsive disorder (OCD):',c:['benztropine (Cogentin) and diphenhydramine (Benadryl).','chlordiazepoxide (Librium) and diazepam (Valium)','fluvoxamine (Luvox) and clomipramine (Anafranil)','divalproex (Depakote) and lithium (Lithobid)'],ci:2,r:'The antidepressants fluvoxamine and clomipramine have been effective in the treatment of OCD. Librium and Valium may be helpful in treating anxiety related to OCD but aren\'t drugs of choice.'},
{s:'np5',t:'Psychiatric Nursing',q:'Alfred was newly diagnosed with anxiety disorder. The physician prescribed buspirone (BuSpar). The teaching instructions should include:',c:['A warning about the drug\'s delayed therapeutic effect, which is from 14 to 30 days.','A warning about the incidence of neuroleptic malignant syndrome (NMS).','A reminder of the need to schedule blood work in 1 week.','A warning that immediate sedation can occur with a resultant drop in pulse.'],ci:0,r:'The client should be informed that the drug\'s therapeutic effect might not be reached for 14 to 30 days. The client must be instructed to continue taking the drug as directed.'},
{s:'np5',t:'Psychiatric Nursing',q:'Richard with agoraphobia has been symptom-free for 4 months. Classic signs and symptoms of phobias include:',c:['Insomnia and an inability to concentrate.','Severe anxiety and fear.','Depression and weight loss.','Withdrawal and failure to distinguish reality from fantasy.'],ci:1,r:'Phobias cause severe anxiety (such as a panic attack) that is out of proportion to the threat of the feared object or situation.'},
{s:'np5',t:'Psychiatric Nursing',q:'Which medications have been found to help reduce or eliminate panic attacks?',c:['Antidepressants','Anticholinergics','Antipsychotics','Mood stabilizers'],ci:0,r:'Tricyclic and monoamine oxidase (MAO) inhibitor antidepressants have been found to be effective in treating clients with panic attacks. Anticholinergic agents relieve physical symptoms of anxiety but don\'t relieve the anxiety itself.'},
{s:'np5',t:'Psychiatric Nursing',q:'A client seeks care because she feels depressed and has gained weight. The physician prescribes tranylcypromine sulfate (Parnate). When this drug is used to treat atypical depression, what is its onset of action?',c:['1 to 2 days','3 to 5 days','6 to 8 days','10 to 14 days'],ci:1,r:'Monoamine oxidase inhibitors, such as tranylcypromine, have an onset of action of approximately 3 to 5 days. A full clinical response may be delayed for 3 to 4 weeks.'},
{s:'np5',t:'Psychiatric Nursing',q:'A 65-year-old client is in the first stage of Alzheimer\'s disease. Nurse Patricia should plan to focus this client\'s care on:',c:['Offering nourishing finger foods to help maintain the client\'s nutritional status.','Providing emotional support and individual counseling.','Monitoring the client to prevent minor illnesses from turning into major problems.','Suggesting new activities for the client and family to do together.'],ci:1,r:'Clients in the first stage of Alzheimer\'s disease are aware that something is happening to them and may become overwhelmed and frightened. Therefore, nursing care typically focuses on providing emotional support and individual counseling.'},
{s:'np5',t:'Psychiatric Nursing',q:'The nurse is assessing a client admitted to the emergency department. Which signs would suggest an overdose of an antianxiety agent?',c:['Combativeness, sweating, and confusion','Agitation, hyperactivity, and grandiose ideation','Emotional lability, euphoria, and impaired memory','Suspiciousness, dilated pupils, and increased blood pressure'],ci:2,r:'Signs of antianxiety agent overdose include emotional lability, euphoria, and impaired memory. Phencyclidine overdose can cause combativeness, sweating, and confusion.'},
{s:'np5',t:'Psychiatric Nursing',q:'The nurse is caring for a client diagnosed with antisocial personality disorder. Which trait would the nurse be most likely to uncover during assessment?',c:['History of gainful employment','Frequent expression of guilt regarding antisocial behavior','Demonstrated ability to maintain close, stable relationships','A low tolerance for frustration'],ci:3,r:'Clients with an antisocial personality disorder exhibit a low tolerance for frustration, emotional immaturity, and a lack of impulse control.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Amy is providing care for a male client undergoing opiate withdrawal. To minimize these effects, opiate users are commonly detoxified with:',c:['Barbiturates','Amphetamines','Methadone','Benzodiazepines'],ci:2,r:'Methadone is used to detoxify opiate users because it binds with opioid receptors at many sites in the CNS but doesn\'t have the same deleterious effects as other opiates.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Cristina is caring for a client who experiences false sensory perceptions with no basis in reality. These perceptions are known as:',c:['Delusions','Hallucinations','Loose associations','Neologisms'],ci:1,r:'Hallucinations are visual, auditory, gustatory, tactile, or olfactory perceptions that have no basis in reality. Delusions are false beliefs. Loose associations are rapid shifts among unrelated ideas.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Marco is developing a plan of care for a client with anorexia nervosa. Which action should the nurse include in the plan?',c:['Restrict visits with the family and friends until the client begins to eat.','Provide privacy during meals.','Set up a strict eating plan for the client.','Encourage the client to exercise, which will reduce her anxiety.'],ci:2,r:'Establishing a consistent eating plan and monitoring the client\'s weight are very important in this disorder. The client should be monitored during meals not given privacy. Exercise must be limited and supervised.'},
{s:'np5',t:'Psychiatric Nursing',q:'Tim is admitted with a diagnosis of delusions of grandeur. The nurse is aware that this diagnosis reflects a belief that one is:',c:['Highly important or famous.','Being persecuted','Connected to events unrelated to oneself','Responsible for the evil in the world.'],ci:0,r:'A delusion of grandeur is a false belief that one is highly important or famous. A delusion of persecution is a false belief that one is being persecuted.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Jen is caring for a male client with manic depression. The plan of care for a client in a manic state would include:',c:['Offering high-calorie meals and strongly encouraging the client to finish all food.','Insisting that the client remain active through the day so that he\'ll sleep at night.','Allowing the client to exhibit hyperactive, demanding, manipulative behavior without setting limits.','Listening attentively with a neutral attitude and avoiding power struggles.'],ci:3,r:'The nurse should listen to the client\'s requests, express willingness to seriously consider the request, and respond later. The nurse should set limits in a calm, clear, and self-confident tone of voice.'},
{s:'np5',t:'Psychiatric Nursing',q:'Ramon is admitted for detoxification after a cocaine overdose. The client tells the nurse that he frequently uses cocaine but that he can control his use if he chooses. Which coping mechanism is he using?',c:['Withdrawal','Logical thinking','Repression','Denial'],ci:3,r:'Denial is an unconscious defense mechanism in which emotional conflict and anxiety is avoided by refusing to acknowledge feelings, desires, impulses, or external facts that are consciously intolerable.'},
{s:'np5',t:'Psychiatric Nursing',q:'Richard is admitted with a diagnosis of schizotypal personality disorder. Which signs would this client exhibit during social situations?',c:['Aggressive behavior','Paranoid thoughts','Emotional affect','Independence needs'],ci:1,r:'Clients with schizotypal personality disorder experience excessive social anxiety that can lead to paranoid thoughts. Their behavior is emotionally cold with a flattened affect.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Mickey is caring for a client diagnosed with bulimia. The most appropriate initial goal for a client diagnosed with bulimia is to:',c:['Avoid shopping for large amounts of food.','Control eating impulses.','Identify anxiety-causing situations','Eat only three meals per day.'],ci:2,r:'Bulimic behavior is generally a maladaptive coping response to stress and underlying issues. The client must identify anxiety-causing situations that stimulate the bulimic behavior and then learn new ways of coping with the anxiety.'},
{s:'np5',t:'Psychiatric Nursing',q:'Rudolf is admitted for an overdose of amphetamines. When assessing the client, the nurse should expect to see:',c:['Tension and irritability','Slow pulse','Hypotension','Constipation'],ci:0,r:'An amphetamine is a nervous system stimulant. An overdose increases tension and irritability. Amphetamines stimulate norepinephrine, which increases the heart rate and blood flow.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nicolas is experiencing hallucinations and tells the nurse, "The voices are telling me I\'m no good." The client asks if the nurse hears the voices. The most appropriate response by the nurse would be:',c:['"It is the voice of your conscience, which only you can control."','"No, I do not hear your voices, but I believe you can hear them."','"The voices are coming from within you and only you can hear them."','"Oh, the voices are a symptom of your illness; don\'t pay any attention to them."'],ci:1,r:'The nurse, demonstrating knowledge and understanding, accepts the client\'s perceptions even though they are hallucinatory.'},
{s:'np5',t:'Psychiatric Nursing',q:'The nurse is aware that the side effect of electroconvulsive therapy that a client may experience:',c:['Loss of appetite','Postural hypotension','Confusion for a time after treatment','Complete loss of memory for a time'],ci:2,r:'The electrical energy passing through the cerebral cortex during ECT results in a temporary state of confusion after treatment.'},
{s:'np5',t:'Psychiatric Nursing',q:'A dying male client gradually moves toward resolution of feelings regarding impending death. Nurse Trish plans to use nonverbal interventions when assessment reveals that the client is in the:',c:['Anger stage','Denial stage','Bargaining stage','Acceptance stage'],ci:3,r:'Communication and intervention during the acceptance stage are mainly nonverbal, as when the client gestures to hold the nurse\'s hand.'},
{s:'np5',t:'Psychiatric Nursing',q:'The outcome that is unrelated to a crisis state is:',c:['Learning more constructive coping skills','Decompensation to a lower level of functioning.','Adaptation and a return to a prior level of functioning.','A higher level of anxiety continuing for more than 3 months.'],ci:3,r:'This is not an expected outcome of a crisis because by definition a crisis would be resolved in 6 weeks.'},
{s:'np5',t:'Psychiatric Nursing',q:'Miranda, a psychiatric client is to be discharged with orders for haloperidol (Haldol) therapy. The nurse should include cautioning the client against:',c:['Driving at night','Staying in the sun','Ingesting wines and cheeses','Taking medications containing aspirin'],ci:1,r:'Haldol causes photosensitivity. Severe sunburn can occur on exposure to the sun.'},
{s:'np5',t:'Psychiatric Nursing',q:'Jen, a nursing student is anxious about the upcoming board examination but is able to study intently and does not become distracted by loud music. The student\'s ability to ignore distractions demonstrates:',c:['Mild-level anxiety','Panic-level anxiety','Severe-level anxiety','Moderate-level anxiety'],ci:3,r:'A moderately anxious person can ignore peripheral events and focuses on central concerns.'},
{s:'np5',t:'Psychiatric Nursing',q:'When assessing premorbid personality characteristics of a client with a major depression, it would be unusual for the nurse to find that this client demonstrated:',c:['Rigidity','Stubbornness','Diverse interest','Overmeticulousness'],ci:2,r:'Before onset of depression, these clients usually have very narrow, limited interest.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Krina recognizes that the suicidal risk for a depressed client is greatest:',c:['As their depression begins to improve','When their depression is most severe','Before any type of treatment is started','As they lose interest in the environment'],ci:0,r:'At this point the client may have enough energy to plan and execute an attempt.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Kate would expect that a client with vascular dementia would experience:',c:['Loss of remote memory related to anoxia','Loss of abstract thinking related to emotional state','Inability to concentrate related to decreased stimuli','Disturbance in recalling recent events related to cerebral hypoxia.'],ci:3,r:'Cell damage seems to interfere with registering input stimuli, which affects the ability to register and recall recent events; vascular dementia is related to multiple vascular lesions.'},
{s:'np5',t:'Psychiatric Nursing',q:'Josefina is to be discharged on a regimen of lithium carbonate. In the teaching plan for discharge the nurse should include:',c:['Advising the client to watch the diet carefully','Suggesting that the client take the pills with milk','Reminding the client that a CBC must be done once a month.','Encouraging the client to have blood levels checked as ordered.'],ci:3,r:'Blood levels must be checked monthly or bimonthly when the client is on maintenance therapy because there is only a small range between therapeutic and toxic levels.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Katrina would be aware that the teaching about the side effects of lithium carbonate were understood when the client states, "I will call my doctor immediately if I notice any:',c:['Sensitivity to bright light or sun','Fine hand tremors or slurred speech','Sexual dysfunction or breast enlargement','Inability to urinate or difficulty when urinating'],ci:1,r:'Fine hand tremors and slurred speech are common side effects of lithium carbonate that indicate toxicity.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Mylene recognizes that the most important factor necessary for the establishment of trust in a critical care area is:',c:['Privacy','Respect','Empathy','Presence'],ci:3,r:'The constant presence of a nurse provides emotional support because the client knows that someone is attentive and available in case of an emergency.'},
{s:'np5',t:'Psychiatric Nursing',q:'When establishing an initial nurse-client relationship, Nurse Hazel should explore with the client the:',c:['Client\'s perception of the presenting problem.','Occurrence of fantasies the client may experience.','Details of any ritualistic acts carried out by the client','Client\'s feelings when external controls are instituted.'],ci:0,r:'The nurse can be most therapeutic by starting where the client is, because it is the client\'s concept of the problem that serves as the starting point of the relationship.'},
{s:'np5',t:'Psychiatric Nursing',q:'Tranylcypromine sulfate (Parnate) is prescribed for a depressed client. Nurse Marian evaluates that learning has occurred when the client states, "I will avoid:',c:['Citrus fruit, tuna, and yellow vegetables.','Chocolate milk, aged cheese, and yogurt','Green leafy vegetables, chicken, and milk.','Whole grains, red meats, and carbonated soda.'],ci:1,r:'These high-tyramine foods, when ingested in the presence of an MAO inhibitor, cause a severe hypertensive response.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse John is aware that most crisis situations should resolve in about:',c:['1 to 2 weeks','4 to 6 weeks','4 to 6 months','6 to 12 months'],ci:1,r:'Crisis is self-limiting and lasts from 4 to 6 weeks.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Judy knows that statistics show that in adolescent suicide behavior:',c:['Females use more dramatic methods than males','Males account for more attempts than do females','Females talk more about suicide before attempting it','Males are more likely to use lethal methods than are females'],ci:3,r:'This finding is supported by research; females account for 90% of suicide attempts but males are three times more successful because of methods used.'},
{s:'np5',t:'Psychiatric Nursing',q:'Dervid with paranoid schizophrenia repeatedly uses profanity during an activity therapy session. Which response by the nurse would be most appropriate?',c:['"Your behavior won\'t be tolerated. Go to your room immediately."','"You\'re just doing this to get back at me for making you come to therapy."','"Your cursing is interrupting the activity. Take time out in your room for 10 minutes."','"I\'m disappointed in you. You can\'t control yourself even for a few minutes."'],ci:2,r:'The nurse should set limits on client behavior to ensure a comfortable environment for all clients. The nurse should accept hostile outbursts within limits without becoming personally offended.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Maureen knows that the nonantipsychotic medication used to treat some clients with schizoaffective disorder is:',c:['phenelzine (Nardil)','chlordiazepoxide (Librium)','lithium carbonate (Lithane)','imipramine (Tofranil)'],ci:2,r:'Lithium carbonate, an antimania drug, is used to treat clients with cyclical schizoaffective disorder. Lithium helps control the affective component of this disorder.'},
{s:'np5',t:'Psychiatric Nursing',q:'Which information is most important for the nurse to include in a teaching plan for a male schizophrenic client taking clozapine (Clozaril)?',c:['Monthly blood tests will be necessary.','Report a sore throat or fever to the physician immediately.','Blood pressure must be monitored for hypertension.','Stop the medication when symptoms subside.'],ci:1,r:'A sore throat and fever are indications of an infection caused by agranulocytosis, a potentially life-threatening complication of clozapine.'},
{s:'np5',t:'Psychiatric Nursing',q:'Ricky with chronic schizophrenia takes neuroleptic medication. Nursing assessment reveals rigidity, fever, hypertension, and diaphoresis. These findings suggest which life-threatening reaction:',c:['Tardive dyskinesia.','Dystonia.','Neuroleptic malignant syndrome.','Akathisia.'],ci:2,r:'The client\'s signs and symptoms suggest neuroleptic malignant syndrome, a life-threatening reaction to neuroleptic medication that requires immediate treatment.'},
{s:'np5',t:'Psychiatric Nursing',q:'Which nursing intervention would be most appropriate if a male client develops orthostatic hypotension while taking amitriptyline (Elavil)?',c:['Consulting with the physician about substituting a different type of antidepressant.','Advising the client to sit up for 1 minute before getting out of bed.','Instructing the client to double the dosage until the problem resolves.','Informing the client that this adverse reaction should disappear within 1 week.'],ci:1,r:'To minimize the effects of amitriptyline-induced orthostatic hypotension, the nurse should advise the client to sit up for 1 minute before getting out of bed.'},
{s:'np5',t:'Psychiatric Nursing',q:'Mr. Cruz visits the physician\'s office seeking treatment for depression, feelings of hopelessness, poor appetite, insomnia, fatigue, low self-esteem, poor concentration, and difficulty making decisions for at least 2 years. The nurse suspects:',c:['Cyclothymic disorder.','Atypical affective disorder.','Major depression.','Dysthymic disorder.'],ci:3,r:'Dysthymic disorder is marked by feelings of depression lasting at least 2 years, accompanied by at least two of the following symptoms: sleep disturbance, appetite disturbance, low energy or fatigue, low self-esteem, poor concentration, difficulty making decisions, and hopelessness.'},
{s:'np5',t:'Psychiatric Nursing',q:'After taking an overdose of phenobarbital (Barbita), Mario is admitted to the emergency department. The physician prescribes activated charcoal (Charcocaps). What is the usual minimum dose of activated charcoal?',c:['5 g mixed in 250 ml of water','15 g mixed in 500 ml of water','30 g mixed in 250 ml of water','60 g mixed in 500 ml of water'],ci:2,r:'The usual adult dosage of activated charcoal is a minimum dose of 30 g, mixed in 250 ml of water.'},
{s:'np5',t:'Psychiatric Nursing',q:'What herbal medication for depression, widely used in Europe, is now being prescribed in the United States?',c:['Ginkgo biloba','Echinacea','St. John\'s wort','Ephedra'],ci:2,r:'St. John\'s wort has been found to have serotonin-elevating properties, similar to prescription antidepressants. Ginkgo biloba is prescribed to enhance mental acuity.'},
{s:'np5',t:'Psychiatric Nursing',q:'Cely with manic episodes is taking lithium. Which electrolyte level should the nurse check before administering this medication?',c:['Calcium','Sodium','Chloride','Potassium'],ci:1,r:'Lithium is chemically similar to sodium. If sodium levels are reduced, such as from sweating or diuresis, lithium will be reabsorbed by the kidneys, increasing the risk of toxicity.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Josefina is caring for a client diagnosed with delirium. Which statement about delirium is true?',c:['It\'s characterized by an acute onset and lasts about 1 month.','It\'s characterized by a slowly evolving onset and lasts about 1 week.','It\'s characterized by a slowly evolving onset and lasts about 1 month.','It\'s characterized by an acute onset and lasts hours to a number of days.'],ci:3,r:'Delirium has an acute onset and typically can last from several hours to several days.'},
{s:'np5',t:'Psychiatric Nursing',q:'Edward, a 66-year-old client is diagnosed with primary degenerative dementia of the Alzheimer\'s type. To assess for progression to the middle stage, the nurse should observe the client for:',c:['Occasional irritable outbursts.','Impaired communication.','Lack of spontaneity.','Inability to perform self-care activities.'],ci:1,r:'Signs of advancement to the middle stage of Alzheimer\'s disease include exacerbated cognitive impairment with obvious personality changes and impaired communication, such as inappropriate conversation, actions, and responses.'},
{s:'np5',t:'Psychiatric Nursing',q:'Isabel with a diagnosis of depression is started on imipramine (Tofranil), 75 mg by mouth at bedtime. The nurse should tell the client that:',c:['This medication may be habit forming and will be discontinued as soon as the client feels better.','This medication has no serious adverse effects.','The client should avoid eating such foods as aged cheeses, yogurt, and chicken livers while taking the medication.','This medication may initially cause tiredness, which should become less bothersome over time.'],ci:3,r:'Sedation is a common early adverse effect of imipramine, a tricyclic antidepressant, and usually decreases as tolerance develops.'},
{s:'np5',t:'Psychiatric Nursing',q:'Kathleen is admitted to the psychiatric clinic for treatment of anorexia nervosa. To promote the client\'s physical health, the nurse should plan to:',c:['Severely restrict the client\'s physical activities.','Weigh the client daily, after the evening meal.','Monitor vital signs, serum electrolyte levels, and acid-base balance.','Instruct the client to keep an accurate record of food and fluid intake.'],ci:2,r:'An anorexic client who requires hospitalization is in poor physical condition from starvation and may die as a result of arrhythmias, hypothermia, malnutrition, infection, or cardiac abnormalities secondary to electrolyte imbalances.'},
{s:'np5',t:'Psychiatric Nursing',q:'Celia with a history of polysubstance abuse is admitted. She complains of nausea and vomiting 24 hours after admission. The nurse assesses piloerection, pupillary dilation, and lacrimation. The nurse suspects:',c:['Alcohol withdrawal','Cannabis withdrawal','Cocaine withdrawal','Opioid withdrawal'],ci:3,r:'The symptoms listed are specific to opioid withdrawal. Alcohol withdrawal would show elevated vital signs. There is no real withdrawal from cannabis.'},
{s:'np5',t:'Psychiatric Nursing',q:'Mr. Garcia, an attorney who throws books and furniture around the office after losing a case, is referred to the psychiatric nurse. This behavior most likely represents the use of which defense mechanism?',c:['Regression','Projection','Reaction-formation','Intellectualization'],ci:0,r:'An adult who throws temper tantrums is displaying regressive behavior, or behavior that is appropriate at a younger age.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Anne is caring for a client treated long term with antipsychotic medication. If tardive dyskinesia is present, Nurse Anne would most likely observe:',c:['Abnormal movements and involuntary movements of the mouth, tongue, and face.','Abnormal breathing through the nostrils accompanied by a thrill.','Severe headache, flushing, tremors, and ataxia.','Severe hypertension, migraine headache.'],ci:0,r:'Tardive dyskinesia is a severe reaction associated with long-term use of antipsychotic medication. The clinical manifestations include abnormal movements (dyskinesia) and involuntary movements of the mouth, tongue, and face.'},
{s:'np5',t:'Psychiatric Nursing',q:'Dennis has a lithium level of 2.4 mEq/L. The nurse immediately would assess the client for which of the following signs or symptoms?',c:['Weakness','Diarrhea','Blurred vision','Fecal incontinence'],ci:2,r:'At lithium levels of 2 to 2.5 mEq/L the client will experience blurred vision, muscle twitching, severe hypotension, and persistent nausea and vomiting.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Jannah is monitoring a male client placed in restraints because of violent behavior. It will be safe to remove the restraints when:',c:['The client verbalizes the reasons for the violent behavior.','The client apologizes and tells the nurse that it will never happen again.','No acts of aggression have been observed within 1 hour after the release of two of the extremity restraints.','The administered medication has taken effect.'],ci:2,r:'The best indicator that the behavior is controlled is if the client exhibits no signs of aggression after partial release of restraints.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Irish is aware that Ritalin is the drug of choice for a child with ADHD. The side effects that may be noted by the nurse:',c:['Increased attention span and concentration','Increase in appetite','Sleepiness and lethargy','Bradycardia and diarrhea'],ci:0,r:'The medication has a paradoxic effect that decreases hyperactivity and impulsivity among children with ADHD. Side effects of Ritalin include anorexia, insomnia, diarrhea and irritability.'},
{s:'np5',t:'Psychiatric Nursing',q:'Kitty, a 9-year-old child has very limited vocabulary and interaction skills. She has an I.Q. of 45. She is diagnosed with Mental retardation of this classification:',c:['Profound','Mild','Moderate','Severe'],ci:2,r:'The child with moderate mental retardation has an I.Q. of 35-50. Profound Mental retardation has an I.Q. of below 20; Mild mental retardation 50-70; Severe mental retardation has an I.Q. of 20-35.'},
{s:'np5',t:'Psychiatric Nursing',q:'The therapeutic approach in the care of Armanda, an autistic child, includes the following EXCEPT:',c:['Engage in diversionary activities when acting-out','Provide an atmosphere of acceptance','Provide safety measures','Rearrange the environment to activate the child'],ci:3,r:'The child with autistic disorder does not want change. Maintaining a consistent environment is therapeutic.'},
{s:'np5',t:'Psychiatric Nursing',q:'Jeremy is brought to the emergency room by friends who state that he took something an hour ago. He is actively hallucinating, agitated, with an irritated nasal septum. The substance most likely taken is:',c:['Heroin','Cocaine','LSD','Marijuana'],ci:1,r:'The manifestations indicate intoxication with cocaine, a CNS stimulant. An irritated nasal septum is characteristic of intranasal cocaine use.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Pauline is aware that Dementia, unlike delirium, is characterized by:',c:['Slurred speech','Insidious onset','Clouding of consciousness','Sensory perceptual change'],ci:1,r:'Dementia has a gradual onset and progressive deterioration. Slurred speech, clouding of consciousness, and sensory perceptual change are all characteristics of delirium.'},
{s:'np5',t:'Psychiatric Nursing',q:'A 35-year-old female has intense fear of riding an elevator. She claims "As if I will die inside." The client is suffering from:',c:['Agoraphobia','Social phobia','Claustrophobia','Xenophobia'],ci:2,r:'Claustrophobia is fear of closed space. Agoraphobia is fear of open space. Social phobia is fear of performing in the presence of others. Xenophobia is fear of strangers.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Myrna develops a counter-transference reaction. This is evidenced by:',c:['Revealing personal information to the client','Focusing on the feelings of the client.','Confronting the client about discrepancies in verbal or non-verbal behavior','The client feels angry towards the nurse who resembles his mother.'],ci:0,r:'Counter-transference is an emotional reaction of the nurse on the client based on her unconscious needs and conflicts.'},
{s:'np5',t:'Psychiatric Nursing',q:'Tristan is on Lithium and has suffered from diarrhea and vomiting. What should the nurse in-charge do first:',c:['Recognize this as a drug interaction','Give the client Cogentin','Reassure the client that these are common side effects of lithium therapy','Hold the next dose and obtain an order for a stat serum lithium level'],ci:3,r:'Diarrhea and vomiting are manifestations of Lithium toxicity. The next dose of lithium should be withheld and a test is done to validate the observation.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Sarah ensures a therapeutic environment for all the clients. Which of the following best describes a therapeutic milieu?',c:['A therapy that rewards adaptive behavior','A cognitive approach to change behavior','A living, learning or working environment.','A permissive and congenial environment'],ci:2,r:'A therapeutic milieu refers to a broad conceptual approach in which all aspects of the environment are channeled to provide a therapeutic environment for the client.'},
{s:'np5',t:'Psychiatric Nursing',q:'Anthony is very hostile toward one of the staff for no apparent reason. He is manifesting:',c:['Splitting','Transference','Countertransference','Resistance'],ci:1,r:'Transference is a positive or negative feeling associated with a significant person in the client\'s past that are unconsciously assigned to another.'},
{s:'np5',t:'Psychiatric Nursing',q:'Marielle, 17 years old, was sexually attacked while on her way home from school. Rape is an example of which type of crisis:',c:['Situational','Adventitious','Developmental','Internal'],ci:1,r:'Adventitious crisis is a crisis involving a traumatic event. It is not part of everyday life.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Greta is aware that the following is classified as an Axis I disorder by the DSM-IV-TR:',c:['Obesity','Borderline personality disorder','Major depression','Hypertension'],ci:2,r:'The DSM-IV-TR classifies major depression as an Axis I disorder. Borderline personality disorder is Axis II; obesity and hypertension are Axis III.'},
{s:'np5',t:'Psychiatric Nursing',q:'Katrina, a newly admitted client is extremely hostile toward a staff member she has just met, without apparent reason. The nurse should suspect that the client is experiencing:',c:['Intellectualization','Transference','Triangulation','Splitting'],ci:1,r:'Transference is the unconscious assignment of negative or positive feelings evoked by a significant person in the client\'s past to another person.'},
{s:'np5',t:'Psychiatric Nursing',q:'An 83-year-old male client in an extended care facility is anxious most of the time and frequently complains of vague symptoms that interfere with his ability to eat. These symptoms indicate which disorder?',c:['Conversion disorder','Hypochondriasis','Severe anxiety','Sublimation'],ci:1,r:'Complaints of vague physical symptoms that have no apparent medical causes are characteristic of clients with hypochondriasis.'},
{s:'np5',t:'Psychiatric Nursing',q:'Charina, a college student frequently visits the health center with multiple vague complaints of GI symptoms before course examinations. Although physical causes have been eliminated, the student continues to express her belief that she has a serious illness. These symptoms are typically of which disorder?',c:['Conversion disorder','Depersonalization','Hypochondriasis','Somatization disorder'],ci:2,r:'Hypochondriasis is shown by the client\'s belief that she has a serious illness, although pathologic causes have been eliminated.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Daisy is aware that the following pharmacologic agent is a sedative hypnotic medication used to induce sleep for a client experiencing a sleep disorder:',c:['Triazolam (Halcion)','Paroxetine (Paxil)','Fluoxetine (Prozac)','Risperidone (Risperdal)'],ci:0,r:'Triazolam is one of a group of sedative hypnotic medication that can be used for a limited time because of the risk of dependence.'},
{s:'np5',t:'Psychiatric Nursing',q:'Aldo with a somatoform pain disorder may obtain secondary gain. Which statement refers to a secondary gain?',c:['It brings some stability to the family','It decreases the preoccupation with the physical illness','It enables the client to avoid some unpleasant activity','It promotes emotional support or attention for the client'],ci:3,r:'Secondary gain refers to the benefits of the illness that allow the client to receive emotional support or attention. Primary gain enables the client to avoid some unpleasant activity.'},
{s:'np5',t:'Psychiatric Nursing',q:'Dervid is diagnosed with panic disorder with agoraphobia. Which statement indicates a positive client response?',c:['"I went to the mall with my friends last Saturday"','"I\'m hyperventilating only when I have a panic attack"','"Today I decided that I can stop taking my medication"','"Last night I decided to eat more than a bowl of cereal"'],ci:0,r:'Clients with panic disorder tend to be socially withdrawn. Going to the mall is a sign of working on avoidance behaviors.'},
{s:'np5',t:'Psychiatric Nursing',q:'The effectiveness of MAO inhibitor drug therapy in a client with PTSD can be demonstrated by which client self-report?',c:['"I\'m sleeping better and don\'t have nightmares"','"I\'m not losing my temper as much"','"I\'ve lost my craving for alcohol"','"I\'ve lost my phobia for water"'],ci:0,r:'MAO inhibitors are used to treat sleep problems, nightmares, and intrusive daytime thoughts in individuals with posttraumatic stress disorder.'},
{s:'np5',t:'Psychiatric Nursing',q:'Mark with a diagnosis of generalized anxiety disorder wants to stop taking his lorazepam (Ativan). Which important fact should nurse Betty discuss with the client?',c:['Stopping the drug may cause depression','Stopping the drug increases cognitive abilities','Stopping the drug decreases sleeping difficulties','Stopping the drug can cause withdrawal symptoms'],ci:3,r:'Stopping antianxiety drugs such as benzodiazepines can cause the client to have withdrawal symptoms.'},
{s:'np5',t:'Psychiatric Nursing',q:'Jennifer, an adolescent who is depressed is brought to the community mental health center. Which of the following other health problems would the nurse suspect?',c:['Anxiety disorder','Behavioral difficulties','Cognitive impairment','Labile moods'],ci:1,r:'Adolescents tend to demonstrate severe irritability and behavioral problems rather than simply a depressed mood.'},
{s:'np5',t:'Psychiatric Nursing',q:'Ricardo, an outpatient in psychiatric facility is diagnosed with dysthymic disorder. Which statement about dysthymic disorder is true?',c:['It involves a mood range from moderate depression to hypomania','It involves a single manic depression','It\'s a form of depression that occurs in the fall and winter','It\'s a mood disorder similar to major depression but of mild to moderate severity'],ci:3,r:'Dysthymic disorder is a mood disorder similar to major depression but it remains mild to moderate in severity.'},
{s:'np5',t:'Psychiatric Nursing',q:'The nurse is aware that the following way vascular dementia differs from Alzheimer\'s disease is:',c:['Vascular dementia has more abrupt onset','The duration of vascular dementia is usually brief','Personality change is common in vascular dementia','The inability to perform motor activities occurs in vascular dementia'],ci:0,r:'Vascular dementia differs from Alzheimer\'s disease in that it has a more abrupt onset and runs a highly variable course.'},
{s:'np5',t:'Psychiatric Nursing',q:'Loretta, a newly admitted client was diagnosed with delirium. She had been taking digoxin, furosemide (Lasix), and diazepam (Valium) for anxiety. This client\'s impairment may be related to which condition?',c:['Infection','Metabolic acidosis','Drug intoxication','Hepatic encephalopathy'],ci:2,r:'This client was taking several medications that have a propensity for producing delirium: digoxin, furosemide, and diazepam.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Ron enters a client\'s room. The client says, "They\'re crawling on my sheets! Get them off my bed!" Which assessment is the most accurate?',c:['The client is experiencing aphasia','The client is experiencing dysarthria','The client is experiencing a flight of ideas','The client is experiencing visual hallucination'],ci:3,r:'The presence of a sensory stimulus without a real object correlates with the definition of a hallucination, which is a false sensory perception.'},
{s:'np5',t:'Psychiatric Nursing',q:'Which of the following descriptions of a client\'s experience and behavior can be assessed as an illusion?',c:['The client tries to hit the nurse when vital signs must be taken','The client says, "I keep hearing a voice telling me to run away"','The client becomes anxious whenever the nurse leaves the bedside','The client looks at the shadow on a wall and tells the nurse she sees frightening faces on the wall.'],ci:3,r:'An illusion is a misinterpretation of an actual sensory stimulus (the shadow on the wall), unlike a hallucination which has no external stimulus.'},
{s:'np5',t:'Psychiatric Nursing',q:'During conversation with a client, the nurse observes that the client shifts from one topic to the next on a regular basis. Which term describes this disorder?',c:['Flight of ideas','Concrete thinking','Ideas of reference','Loose association'],ci:3,r:'Loose associations are conversations that constantly shift in topic. Flight of ideas is characterized by conversation that\'s disorganized from the onset.'},
{s:'np5',t:'Psychiatric Nursing',q:'Francis tells the nurse that her coworkers are sabotaging the computer. When the nurse asks questions, the client becomes argumentative. This behavior shows personality traits associated with which personality disorder?',c:['Antisocial','Histrionic','Paranoid','Schizotypal'],ci:2,r:'Because of their suspiciousness, paranoid personalities ascribe malevolent activities to others and tend to be defensive, becoming quarrelsome and argumentative.'},
{s:'np5',t:'Psychiatric Nursing',q:'Which intervention is important for a client with paranoid personality disorder taking olanzapine (Zyprexa)?',c:['Explain effects of serotonin syndrome','Teach the client to watch for extrapyramidal adverse reaction','Explain that the drug is less effective if the client smokes','Discuss the need to report paradoxical effects such as euphoria'],ci:2,r:'Olanzapine (Zyprexa) is less effective for clients who smoke cigarettes.'},
{s:'np5',t:'Psychiatric Nursing',q:'Nurse Alexandra notices other clients on the unit avoiding a client diagnosed with antisocial personality disorder. When discussing appropriate behavior in group therapy, which comment is expected about this client by his peers?',c:['Lack of honesty','Belief in superstition','Show of temper tantrums','Constant need for attention'],ci:0,r:'Clients with antisocial personality disorder tend to engage in acts of dishonesty, shown by lying.'},
{s:'np5',t:'Psychiatric Nursing',q:'Tommy with dependent personality disorder is working to increase his self-esteem. Which statement by Tommy shows teaching was successful?',c:['"I\'m not going to look just at the negative things about myself"','"I\'m most concerned about my level of competence and progress"','"I\'m not as envious of the things other people have as I used to be"','"I find I can\'t stop myself from taking over things others should be doing"'],ci:0,r:'As the client makes progress on improving self-esteem, self-blame and negative self-evaluation will decrease.'},
{s:'np5',t:'Psychiatric Nursing',q:'Norma, a 42-year-old client with chronic undifferentiated schizophrenia scratches while telling the nurse she feels creatures eating away at her skin. Which intervention should be done first?',c:['Talk about her hallucinations and fears','Refer her for anticholinergic adverse reactions','Assess for possible physical problems such as rash','Call her physician to get her medication increased'],ci:2,r:'Clients with schizophrenia generally have poor visceral recognition. They need to have an in-depth assessment of physical complaints that may spill over into their delusional symptoms.'},
{s:'np5',t:'Psychiatric Nursing',q:'Ivy, who is on the psychiatric unit, is copying and imitating the movements of her primary nurse. This behavior is known by which term?',c:['Modeling','Echopraxia','Ego-syntonicity','Ritualism'],ci:1,r:'Echopraxia is the copying of another\'s behaviors and is the result of the loss of ego boundaries. Modeling is the conscious copying of someone\'s behaviors.'},
{s:'np5',t:'Psychiatric Nursing',q:'Jun approaches the nurse and tells that he hears a voice telling him that he\'s evil and deserves to die. Which term describes the client\'s perception?',c:['Delusion','Disorganized speech','Hallucination','Idea of reference'],ci:2,r:'Hallucinations are sensory experiences that are misrepresentations of reality or have no basis in reality. Delusions are beliefs not based in reality.'},
{s:'np5',t:'Psychiatric Nursing',q:'Mike is admitted to a psychiatric unit with a diagnosis of undifferentiated schizophrenia. Which defense mechanism is probably used by Mike?',c:['Projection','Rationalization','Regression','Repression'],ci:2,r:'Regression, a return to earlier behavior to reduce anxiety, is the basic defense mechanism in schizophrenia.'},
{s:'np5',t:'Psychiatric Nursing',q:'Rocky has started taking haloperidol (Haldol). Which instruction is most appropriate before taking haloperidol?',c:['Should report feelings of restlessness or agitation at once','Use a sunscreen outdoors on a year-round basis','Be aware you\'ll feel increased energy taking this drug','This drug will indirectly control essential hypertension'],ci:0,r:'Agitation and restlessness are adverse effects of haloperidol and can be treated with anticholinergic drugs.'},
];
async function seed() {
  const client = await pool.connect();
  let count = 0;
  try {
    for (const q of questions) {
      await client.query(
        `INSERT INTO quiz_items (subject_code, topic_name, question, choices, correct_index, rationale, difficulty) VALUES ($1,$2,$3,$4,$5,$6,'medium')`,
        [q.s, q.t, q.q, JSON.stringify(q.c), q.ci, q.r]
      );
      count++;
    }
    console.log(`✅ Inserted ${count} NP5 questions from actual PNLE reviewer!`);
  } finally {
    client.release();
    await pool.end();
  }
}
seed().catch(console.error);
